#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long modpow(long long a, long long e) {
    long long r = 1;
    while (e) {
        if (e & 1) r = r * a % MOD;
        a = a * a % MOD;
        e >>= 1;
    }
    return r;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int k = N / 2;
        char *vis = (char*)calloc(N + 1, sizeof(char));
        int cycles = 0;
        for (int i = 1; i <= N; ++i) {
            if (!vis[i]) {
                ++cycles;
                int cur = i;
                while (!vis[cur]) {
                    vis[cur] = 1;
                    if (cur % 2 == 0) cur = cur / 2;
                    else cur = k + (cur + 1) / 2;
                }
            }
        }
        free(vis);
        printf("%lld\n", modpow(26, cycles));
    }
    return 0;
}

