code.Python3:
import sys
MOD = 1000000007

def mod_pow(a, e):
    r = 1
    while e:
        if e & 1:
            r = r * a % MOD
        a = a * a % MOD
        e >>= 1
    return r

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        k = N // 2
        visited = [False] * (N + 1)
        cycles = 0
        for i in range(1, N + 1):
            if not visited[i]:
                cycles += 1
                cur = i
                while not visited[cur]:
                    visited[cur] = True
                    if cur % 2 == 0:
                        cur //= 2
                    else:
                        cur = k + (cur + 1) // 2
        out.append(str(mod_pow(26, cycles)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

