const fs = require('fs');
const MOD = 1000000007n;
function modPow(a, e) {
  let r = 1n;
  let base = BigInt(a);
  let exp = BigInt(e);
  while (exp > 0n) {
    if (exp & 1n) r = (r * base) % MOD;
    base = (base * base) % MOD;
    exp >>= 1n;
  }
  return r;
}
